namespace sv_88640fb3e7604afa9a55bfa225c4d86b.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@namespace sv_88640fb3e7604afa9a55bfa225c4d86b.Components.Chat

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-name-row">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-description">@TruncatedDescription</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public required Services.Channel Channel { get; set; }
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;
}

@namespace sv_88640fb3e7604afa9a55bfa225c4d86b.Components.Chat

@if (Reactions.Any())
{
    <div class="reaction-bar">
        @foreach (var reaction in Reactions)
        {
            <button class="reaction-badge" @onclick="() => OnReactionClicked.InvokeAsync(reaction.Emoji)"
                    title="@string.Join(", ", reaction.Users)">
                @reaction.Emoji @reaction.Users.Count
            </button>
        }
    </div>
}

@code {
    [Parameter, EditorRequired] public required List<Services.Reaction> Reactions { get; set; }
    [Parameter] public EventCallback<string> OnReactionClicked { get; set; }
}

@namespace sv_88640fb3e7604afa9a55bfa225c4d86b.Components.Chat

@if (Visible)
{
    <div class="emoji-picker">
        @foreach (var emoji in _emojis)
        {
            <button class="emoji-btn" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)">
                @emoji
            </button>
        }
    </div>
}

@code {
    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    [Parameter] public bool Visible { get; set; }
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }
}

@namespace sv_88640fb3e7604afa9a55bfa225c4d86b.Components.Chat

<div class="message-input">
    <textarea @bind="Text" @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="send-btn" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string Text { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var content = Text.Trim();
        Text = "";
        await OnSend.InvokeAsync(content);
    }
}

