@namespace sv_88640fb3e7604afa9a55bfa225c4d86b.Components.Chat

<div class="message-bubble @(IsThreadStarter ? "thread-starter" : "")"
     @onmouseenter="() => _showActions = true"
     @onmouseleave="HideActions">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    <ReactionBar Reactions="Message.Reactions" OnReactionClicked="HandleReaction" />

    @if (IsThreadStarter && ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😊
            </button>
        </div>
        <EmojiPicker Visible="_showEmojiPicker" OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired] public required Services.Message Message { get; set; }
    [Parameter] public bool IsThreadStarter { get; set; }
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleReaction(string emoji)
    {
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@namespace sv_88640fb3e7604afa9a55bfa225c4d86b.Components.Chat

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public required List<Services.Channel> Channels { get; set; }
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

@namespace sv_88640fb3e7604afa9a55bfa225c4d86b.Components.Chat

<div class="message-list" @onscroll="HandleScroll" @ref="_listElement">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    @foreach (var message in Messages)
    {
        var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == message.Id);
        <MessageBubble Message="message"
                       IsThreadStarter="summary is not null || message.ReplyToId is null"
                       ReplyCount="summary?.ReplyCount ?? 0"
                       OnOpenThread="OnOpenThread"
                       OnReact="OnReact" />
    }
</div>

