arguments.file_text:
@page "/chat"
@using sv_88640fb3e7604afa9a55bfa225c4d86b.Components.Chat
@using sv_88640fb3e7604afa9a55bfa225c4d86b.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_threadOpen ? "with-thread" : "")">
        @if (_selectedChannel is not null)
        {
            <MessageArea ChannelName="@_selectedChannel.Name"
                         ChannelDescription="@_selectedChannel.Description"
                         Messages="_messages"
                         ThreadSummaries="_threadSummaries"
                         IsLoadingMore="_isLoadingMore"
                         OnLoadMore="LoadMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];

    private int _selectedChannelId;
    private Channel? _selectedChannel;
    private int _messageSkip;
    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messageSkip = 0;
        _hasMoreMessages = true;
        _messages = [];
        CloseThread();

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _messageSkip = messages.Count;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update local unread count
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || !_hasMoreMessages || _selectedChannel is null) return;

        _isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(_selectedChannelId, _messageSkip, PageSize);
        if (older.Count < PageSize)
        {
            _hasMoreMessages = false;
        }

        _messages.InsertRange(0, older);
        _messageSkip += older.Count;
        _isLoadingMore = false;

        BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;

        var message = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
        _messages.Add(message);
        _messageSkip++;
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _selectedChannel is null) return;

        var reply = await ChatService.SendMessageAsync(_selectedChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);
        _messages.Add(reply);
        _messageSkip++;

        BuildThreadSummaries();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        // Optimistically update the local message
        UpdateReactionLocally(args.MessageId, args.Emoji);
    }

    private void UpdateReactionLocally(int messageId, string emoji)
    {
        UpdateReactionInList(_messages, messageId, emoji);
        UpdateReactionInList(_threadReplies, messageId, emoji);
    }

    private static void UpdateReactionInList(List<Message> list, int messageId, string emoji)
    {
        var idx = list.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = list[idx];
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private void BuildThreadSummaries()
    {
        // Build thread summaries from reply messages
        _threadSummaries = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
    }
